#include <stdio.h>
#include <string.h>
#define MAXLEN 105

void strip_newline(char *s){
    size_t len = strlen(s);
    if(len && s[len-1]=='\n') s[len-1]='\0';
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0; getchar(); // consume newline after T
    for(int tc=0; tc<T; ++tc){
        char type; type = getchar(); getchar(); // consume newline after type
        char title[MAXLEN], author[MAXLEN];
        fgets(title, MAXLEN, stdin); strip_newline(title);
        fgets(author, MAXLEN, stdin); strip_newline(author);
        if(type=='B'){
            printf("Title: %s, Author: %s\n", title, author);
        } else if(type=='E'){
            char sizeStr[MAXLEN];
            fgets(sizeStr, MAXLEN, stdin); strip_newline(sizeStr);
            int size = atoi(sizeStr);
            printf("Title: %s, Author: %s, File Size (MB): %d\n", title, author, size);
        }
    }
    return 0;
}

