#include <bits/stdc++.h>
using namespace std;

class Book {
public:
    string title, author;
    Book(const string& t, const string& a): title(t), author(a) {}
    virtual void display() const {
        cout << "Title: " << title << ", Author: " << author;
    }
    virtual ~Book() = default;
};

class EBook : public Book {
public:
    long long size;
    EBook(const string& t, const string& a, long long s): Book(t,a), size(s) {}
    void display() const override {
        Book::display();
        cout << ", File Size (MB): " << size;
    }
};

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0; string line; getline(cin,line); // consume endline
    for(int tc=0; tc<T; ++tc){
        char type; cin>>type; getline(cin,line); // consume endline after type
        string title, author; getline(cin,title); getline(cin,author);
        if(type=='B'){
            Book b(title,author);
            b.display();
            cout << '\n';
        } else if(type=='E'){
            long long sz; cin>>sz; getline(cin,line); // consume endline after size
            EBook e(title,author,sz);
            e.display();
            cout << '\n';
        }
    }
    return 0;
}

