import java.io.*;
import java.util.*;

class Book {
    String title, author;
    Book(String t, String a){ this.title = t; this.author = a; }
    void display(StringBuilder sb){
        sb.append("Title: ").append(title).append(", Author: ").append(author);
    }
}

class EBook extends Book {
    int size;
    EBook(String t, String a, int s){ super(t,a); this.size = s; }
    @Override
    void display(StringBuilder sb){
        super.display(sb);
        sb.append(", File Size (MB): ").append(size);
    }
}

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for(int i=0;i<T;i++){
            char type = br.readLine().trim().charAt(0);
            String title = br.readLine();
            String author = br.readLine();
            if(type=='B'){
                Book b = new Book(title, author);
                b.display(out);
                out.append('\n');
            } else { // E
                int size = Integer.parseInt(br.readLine().trim());
                EBook e = new EBook(title, author, size);
                e.display(out);
                out.append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

class Book:
    def __init__(self, title, author):
        self.title = title
        self.author = author
    def display(self):
        return f"Title: {self.title}, Author: {self.author}"

class EBook(Book):
    def __init__(self, title, author, size):
        super().__init__(title, author)
        self.size = size
    def display(self):
        return f"Title: {self.title}, Author: {self.author}, File Size (MB): {self.size}"

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    idx = 0
    T = int(data[idx].strip()); idx += 1
    out_lines = []
    for _ in range(T):
        typ = data[idx].strip(); idx += 1
        title = data[idx].rstrip('\n'); idx += 1
        author = data[idx].rstrip('\n'); idx += 1
        if typ == 'B':
            book = Book(title, author)
        else:  # 'E'
            size = int(data[idx].strip()); idx += 1
            book = EBook(title, author, size)
        out_lines.append(book.display())
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

